var grids=[];
var xAxes=[];
var yAxes=[];
var series=[];
transformedData.forEach(function(r,i){
  grids.push({left:'15%',right:'5%',top:(10+i*30)+'%',height:'22%'});
  xAxes.push({type:'category',data:r.vals.map(function(_,j){return 'D'+(j+1);}),gridIndex:i,show:false});
  var minV=Math.min.apply(null,r.vals);
  var maxV=Math.max.apply(null,r.vals);
  yAxes.push({type:'value',gridIndex:i,min:minV*0.95,max:maxV*1.05,show:false});
  series.push({type:'line',data:r.vals,xAxisIndex:i,yAxisIndex:i,symbol:'none',lineStyle:{width:2},areaStyle:{opacity:0.15},name:r.label});
});
option={title:{text:'Stock Sparklines',left:'center'},grid:grids,xAxis:xAxes,yAxis:yAxes,series:series};
